 36Ôćĺ  });
 37Ôćĺ
 38Ôćĺ  const streakQuery = useQuery({
 39Ôćĺ    queryKey: ['streak', user?.id],
 40Ôćĺ    enabled: Boolean(user?.id),
 41Ôćĺ    queryFn: () => mobileApi.getStreak(user?.id ?? ''),
 42Ôćĺ  });
 43Ôćĺ
 44Ôćĺ  const profile = userDataQuery.data?.userData?.[0] ?? null;
 45Ôćĺ  const streak = streakQuery.data?.currentStreak;
 46Ôćĺ
 47Ôćĺ  const parsedBg = useMemo(
