 54Ôćĺ      {text: 'Cancel', style: 'cancel'},
 55Ôćĺ      {
 56Ôćĺ        text: 'Sign Out',
 57Ôćĺ        style: 'destructive',
 58Ôćĺ        onPress: async () => {
 59Ôćĺ          try {
 60Ôćĺ            await signOut();
 61Ôćĺ          } catch (error) {
 62Ôćĺ            Alert.alert(
 63Ôćĺ              'Sign out failed',
