161Ôćĺfunction LoggedInShell({children}: {children: React.ReactNode}) {
162Ôćĺ  const {session} = useAuth();
163Ôćĺ  const userId = session?.user.id;
164Ôćĺ  const [toast, setToast] = useState<{message: string; visible: boolean}>({
165Ôćĺ    message: '',
166Ôćĺ    visible: false,
167Ôćĺ  });
168Ôćĺ
169Ôćĺ  const handleNewNotification = useCallback((payload: Record<string, unknown>) => {
170Ôćĺ    const message =
171Ôćĺ      (payload.message as string) || 'You have a new notification';
172Ôćĺ    setToast({message, visible: true});
173Ôćĺ  }, []);
174Ôćĺ
175Ôćĺ  const handleDismissToast = useCallback(() => {
176Ôćĺ    setToast(prev => ({...prev, visible: false}));
177Ôćĺ  }, []);
178Ôćĺ
179Ôćĺ  useRealtimeNotifications(userId, {
180Ôćĺ    onNewNotification: handleNewNotification,
181Ôćĺ  });
182Ôćĺ
183Ôćĺ  return (
184Ôćĺ    <View style={styles.shellContainer}>
185Ôćĺ      {children}
186Ôćĺ      <Toast
187Ôćĺ        message={toast.message}
